{
  "name": "Marché & Menu",
  "description": "Une application de planification de repas intelligente qui génère des menus hebdomadaires et des listes de courses adaptées à votre supermarché local en utilisant l'IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Meal {
  name: string;
  description: string;
  cookingTimeMinutes: number;
}

export interface DayPlan {
  day: string;
  breakfast: Meal;
  lunch: Meal;
  dinner: Meal;
}

export interface ShoppingItem {
  item: string;
  quantity: string;
  category: string;
  notes?: string;
  estimatedPrice?: string;
}

export interface WeeklyPlanResponse {
  locationConfirmed: string;
  supermarketContext: string;
  weeklyPlan: DayPlan[];
  shoppingList: ShoppingItem[];
}

export interface UserInput {
  address: string;
  supermarket: string;
}

export enum AppState {
  IDLE,
  LOADING,
  SUCCESS,
  ERROR
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { WeeklyPlanResponse, UserInput } from "../types";

const apiKey = process.env.API_KEY;

if (!apiKey) {
  console.error("API Key is missing. Please ensure process.env.API_KEY is available.");
}

const ai = new GoogleGenAI({ apiKey: apiKey });

const responseSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    locationConfirmed: {
      type: Type.STRING,
      description: "Le nom et l'adresse du supermarché spécifique identifié via Google Maps."
    },
    supermarketContext: {
      type: Type.STRING,
      description: "Une brève note sur la disponibilité des produits dans cette enseigne/localité (ex: 'Ce Monoprix a une large section bio')."
    },
    weeklyPlan: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day: { type: Type.STRING, description: "Jour de la semaine (Lundi, Mardi...)" },
          breakfast: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              cookingTimeMinutes: { type: Type.NUMBER }
            }
          },
          lunch: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              cookingTimeMinutes: { type: Type.NUMBER }
            }
          },
          dinner: {
            type: Type.OBJECT,
            properties: {
              name: { type: Type.STRING },
              description: { type: Type.STRING },
              cookingTimeMinutes: { type: Type.NUMBER }
            }
          }
        }
      }
    },
    shoppingList: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          category: { type: Type.STRING, description: "Catégorie (Fruits, Légumes, Épicerie, etc.)" },
          item: { type: Type.STRING, description: "Nom du produit" },
          quantity: { type: Type.STRING, description: "Quantité estimée" },
          notes: { type: Type.STRING, description: "Conseil spécifique pour l'achat dans ce supermarché" },
          estimatedPrice: { type: Type.STRING, description: "Prix estimé si disponible, sinon laisser vide" }
        }
      }
    }
  },
  required: ["locationConfirmed", "weeklyPlan", "shoppingList"]
};

export const generateWeeklyPlan = async (input: UserInput): Promise<WeeklyPlanResponse> => {
  if (!apiKey) throw new Error("API Key required");

  const prompt = `
    Agis comme un chef personnel et un expert en logistique alimentaire.

    L'utilisateur habite à : "${input.address}"
    Son supermarché préféré est : "${input.supermarket}"

    TÂCHES:
    1. Utilise Google Maps pour localiser précisément ce supermarché près de l'adresse indiquée. Confirme l'adresse exacte trouvée.
    2. Crée un plan de repas pour 7 jours (Lundi à Dimanche). Les repas doivent être équilibrés, sains, variés et utiliser des produits de saison.
    3. Génère la liste de courses COMPLETE pour réaliser ces 21 repas.
    4. ADAPTATION LOCALE : Assure-toi que les ingrédients listés sont typiquement disponibles dans l'enseigne "${input.supermarket}" en France.

    Format de réponse JSON strict requis.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }], // Use Maps to find the store
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    if (response.text) {
      return JSON.parse(response.text) as WeeklyPlanResponse;
    } else {
      throw new Error("No response text generated");
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { UserInput } from '../types';
import { motion } from 'framer-motion';

interface InputSectionProps {
  onSubmit: (data: UserInput) => void;
  isLoading: boolean;
}

export const InputSection: React.FC<InputSectionProps> = ({ onSubmit, isLoading }) => {
  const [address, setAddress] = useState('');
  const [supermarket, setSupermarket] = useState('');

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (address && supermarket) {
      onSubmit({ address, supermarket });
    }
  };

  return (
    <motion.div 
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.8, ease: "easeOut" }}
      className="w-full max-w-xl mx-auto"
    >
      <div className="bg-white/80 backdrop-blur-md paper-texture p-8 md:p-12 rounded-2xl shadow-[0_20px_40px_-15px_rgba(0,0,0,0.1)] border border-stone-100 relative overflow-hidden">
        {/* Decorative elements */}
        <div className="absolute top-0 right-0 w-32 h-32 bg-[#588157]/5 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>
        <div className="absolute bottom-0 left-0 w-24 h-24 bg-[#C8553D]/5 rounded-full blur-2xl -ml-10 -mb-10 pointer-events-none"></div>

        <div className="relative z-10">
          <h2 className="text-3xl md:text-4xl font-serif text-[#2C2C2C] mb-3 leading-tight">
            Préparez votre semaine
          </h2>
          <p className="text-stone-500 mb-8 font-light text-lg">
            Des menus équilibrés et une liste de courses intelligente, adaptés à votre quartier.
          </p>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-2 group">
              <label htmlFor="address" className="block text-sm font-medium tracking-wide text-stone-600 uppercase">
                Votre Adresse
              </label>
              <div className="relative">
                <input
                  type="text"
                  id="address"
                  value={address}
                  onChange={(e) => setAddress(e.target.value)}
                  placeholder="10 Rue de la Paix, Paris..."
                  disabled={isLoading}
                  className="w-full bg-[#F9F8F6] border-b-2 border-stone-200 px-4 py-3 text-lg outline-none transition-colors focus:border-[#C8553D] focus:bg-white placeholder-stone-300 rounded-t-lg"
                  required
                />
              </div>
            </div>

            <div className="space-y-2 group">
              <label htmlFor="supermarket" className="block text-sm font-medium tracking-wide text-stone-600 uppercase">
                Supermarché Préféré
              </label>
              <div className="relative">
                <input
                  type="text"
                  id="supermarket"
                  value={supermarket}
                  onChange={(e) => setSupermarket(e.target.value)}
                  placeholder="Monoprix, Carrefour City, Biocoop..."
                  disabled={isLoading}
                  className="w-full bg-[#F9F8F6] border-b-2 border-stone-200 px-4 py-3 text-lg outline-none transition-colors focus:border-[#588157] focus:bg-white placeholder-stone-300 rounded-t-lg"
                  required
                />
              </div>
            </div>

            <div className="pt-6">
              <button
                type="submit"
                disabled={isLoading}
                className={`w-full py-4 px-6 rounded-lg text-white font-medium text-lg tracking-wide transition-all transform duration-300
                  ${isLoading 
                    ? 'bg-stone-300 cursor-not-allowed scale-95' 
                    : 'bg-[#2C2C2C] hover:bg-black hover:shadow-lg hover:-translate-y-1 active:scale-95'
                  }`}
              >
                {isLoading ? (
                  <span className="flex items-center justify-center gap-3">
                    <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
                    </svg>
                    Analyse du quartier...
                  </span>
                ) : (
                  "Générer mon Menu"
                )}
              </button>
            </div>
          </form>
        </div>
      </div>
    </motion.div>
  );
};

import React from 'react';
import { DayPlan } from '../types';
import { motion } from 'framer-motion';

interface PlanDisplayProps {
  plan: DayPlan[];
  supermarketContext: string;
  locationConfirmed: string;
}

const MealCard: React.FC<{ title: string; meal: any; delay: number }> = ({ title, meal, delay }) => (
  <motion.div 
    initial={{ opacity: 0, y: 10 }}
    animate={{ opacity: 1, y: 0 }}
    transition={{ delay, duration: 0.4 }}
    className="mb-4 last:mb-0 group"
  >
    <div className="flex items-baseline justify-between mb-1">
      <span className="text-xs font-bold text-[#C8553D] tracking-widest uppercase">{title}</span>
      <span className="text-xs text-stone-400 flex items-center gap-1">
        <svg xmlns="http://www.w3.org/2000/svg" className="h-3 w-3" viewBox="0 0 20 20" fill="currentColor">
          <path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zm1-12a1 1 0 10-2 0v4a1 1 0 00.293.707l2.828 2.829a1 1 0 101.415-1.415L11 9.586V6z" clipRule="evenodd" />
        </svg>
        {meal.cookingTimeMinutes}m
      </span>
    </div>
    <h4 className="font-serif text-lg leading-tight text-stone-800 group-hover:text-[#588157] transition-colors duration-200">
      {meal.name}
    </h4>
    <p className="text-sm text-stone-500 mt-1 leading-relaxed line-clamp-2">
      {meal.description}
    </p>
  </motion.div>
);

export const PlanDisplay: React.FC<PlanDisplayProps> = ({ plan, supermarketContext, locationConfirmed }) => {
  return (
    <div className="w-full">
      <div className="mb-10 text-center">
        <motion.div
           initial={{ opacity: 0 }}
           animate={{ opacity: 1 }}
           transition={{ duration: 1 }}
        >
            <h2 className="text-4xl font-serif text-[#2C2C2C] mb-4">La Carte de la Semaine</h2>
            <div className="inline-block bg-white px-6 py-3 rounded-full shadow-sm border border-stone-200">
                <p className="text-sm text-stone-600 flex items-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4 text-[#588157]" viewBox="0 0 20 20" fill="currentColor">
                    <path fillRule="evenodd" d="M5.05 4.05a7 7 0 119.9 9.9L10 18.9l-4.95-4.95a7 7 0 010-9.9zM10 11a2 2 0 100-4 2 2 0 000 4z" clipRule="evenodd" />
                </svg>
                <span className="font-semibold">{locationConfirmed}</span>
                <span className="w-1 h-1 bg-stone-300 rounded-full mx-1"></span>
                <span className="italic font-light">{supermarketContext}</span>
