import { GoogleGenAI } from "@google/genai";
import { WeeklyPlanResponse, UserInput } from "../types";

const apiKey = process.env.API_KEY;

if (!apiKey) {
  console.error("API Key is missing. Please ensure process.env.API_KEY is available.");
}

const ai = new GoogleGenAI({ apiKey: apiKey });

export const generateWeeklyPlan = async (input: UserInput): Promise<WeeklyPlanResponse> => {
  if (!apiKey) throw new Error("API Key required");

  const prompt = `
    Agis comme un chef personnel et un expert en logistique alimentaire.

    L'utilisateur habite à : "${input.address}"
    Son supermarché préféré est : "${input.supermarket}"

    TÂCHES:
    1. Utilise Google Maps pour localiser précisément ce supermarché près de l'adresse indiquée. Confirme l'adresse exacte trouvée.
    2. Crée un plan de repas pour 7 jours (Lundi à Dimanche). Les repas doivent être équilibrés, sains, variés et utiliser des produits de saison.
    3. Génère la liste de courses COMPLETE pour réaliser ces 21 repas.
    4. ADAPTATION LOCALE : Assure-toi que les ingrédients listés sont typiquement disponibles dans l'enseigne "${input.supermarket}" en France.

    FORMAT DE RÉPONSE:
    Retourne UNIQUEMENT un objet JSON valide correspondant à l'interface suivante, sans texte additionnel ni markdown:
    {
      "locationConfirmed": "Nom et adresse confirmée du supermarché",
      "supermarketContext": "Brève note sur ce supermarché",
      "weeklyPlan": [
        {
          "day": "Lundi",
          "breakfast": { "name": "...", "description": "...", "cookingTimeMinutes": 10 },
          "lunch": { "name": "...", "description": "...", "cookingTimeMinutes": 20 },
          "dinner": { "name": "...", "description": "...", "cookingTimeMinutes": 30 }
        }
      ],
      "shoppingList": [
        {
          "category": "Fruits",
          "item": "Pommes",
          "quantity": "1kg",
          "notes": "Bio si possible",
          "estimatedPrice": "3€"
        }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        // responseMimeType and responseSchema are NOT allowed when using googleMaps
      },
    });

    if (response.text) {
      let jsonStr = response.text.trim();
      // Remove markdown code blocks if present
      if (jsonStr.startsWith("```json")) {
        jsonStr = jsonStr.replace(/^```json\n?/, "").replace(/\n?```$/, "");
      } else if (jsonStr.startsWith("```")) {
        jsonStr = jsonStr.replace(/^```\n?/, "").replace(/\n?```$/, "");
      }
      return JSON.parse(jsonStr) as WeeklyPlanResponse;
    } else {
      throw new Error("No response text generated");
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

