import { GoogleGenAI } from "@google/genai";
import { WeeklyPlanResponse, UserInput } from "../types";

const apiKey = process.env.API_KEY;

if (!apiKey) {
  console.error("API Key is missing. Please ensure process.env.API_KEY is available.");
}

const ai = new GoogleGenAI({ apiKey: apiKey });

export const generateWeeklyPlan = async (input: UserInput): Promise<WeeklyPlanResponse> => {
  if (!apiKey) throw new Error("API Key required");

  const prompt = `
    Agis comme un chef personnel et un expert en logistique alimentaire.

    INFORMATIONS UTILISATEUR:
    - Adresse : "${input.address}"
    - Supermarché cible : "${input.supermarket}"
    - Nombre de personnes : ${input.peopleCount} (C'est TRÈS IMPORTANT pour les quantités)
    ${input.budget ? `- Budget Maximum souhaité : ${input.budget}` : ''}
    ${input.diet ? `- Régime spécifique : ${input.diet}` : ''}
    ${input.unwantedIngredients ? `- Ingrédients non souhaités/Allergies : ${input.unwantedIngredients}` : ''}

    TÂCHES:
    1. **Localisation** : Utilise Google Maps pour localiser ce supermarché précis près de l'adresse.
    2. **Menu** : Crée un plan de 7 jours (21 repas). 
       - Adapte les portions pour ${input.peopleCount} personnes.
       - Respecte STRICTEMENT le budget et le régime indiqués.
       - Chaque repas DOIT contenir une recette complète (ingrédients + instructions).
    3. **Courses** : Génère la liste de courses pour ces repas.
       - **QUANTITÉS** : Calcule les quantités exactes pour ${input.peopleCount} personnes. (Ex: "500g" au lieu de "100g").
       - **PRIX** : Estime le prix de CHAQUE article selon les tarifs moyens de l'enseigne "${input.supermarket}" en France.
       - Le total doit rentrer dans le budget si précisé.

    FORMAT DE RÉPONSE ATTENDU (JSON STRICT UNIQUEMENT):
    {
      "locationConfirmed": "Nom et adresse précise du magasin trouvé",
      "supermarketContext": "Note sur l'enseigne (ex: 'Ce magasin est cher', 'Large choix bio')",
      "weeklyPlan": [
        {
          "day": "Lundi",
          "breakfast": { 
            "name": "Nom du plat", 
            "description": "Courte description", 
            "cookingTimeMinutes": 10,
            "recipe": {
                "ingredients": ["4 oeufs (pour 2 pers)", "20g beurre"],
                "instructions": ["Battre les oeufs", "Cuire à la poêle"]
            }
          },
          "lunch": { ... },
          "dinner": { ... }
        }
      ],
      "shoppingList": [
        {
          "category": "Produits Frais",
          "item": "Lait",
          "quantity": "2L",
          "notes": "Demi-écrémé",
          "estimatedPrice": 2.40  // NOMBRE (float) en Euros, pas de chaine
        }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
      },
    });

    if (response.text) {
      let jsonStr = response.text.trim();
      if (jsonStr.startsWith("```json")) {
        jsonStr = jsonStr.replace(/^```json\n?/, "").replace(/\n?```$/, "");
      } else if (jsonStr.startsWith("```")) {
        jsonStr = jsonStr.replace(/^```\n?/, "").replace(/\n?```$/, "");
      }
      return JSON.parse(jsonStr) as WeeklyPlanResponse;
    } else {
      throw new Error("No response text generated");
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

