import React, { useState } from 'react';
import { ShoppingItem } from '../types';
import { motion } from 'framer-motion';

interface ShoppingListProps {
  items: ShoppingItem[];
}

export const ShoppingList: React.FC<ShoppingListProps> = ({ items }) => {
  // Group items by category
  const groupedItems = items.reduce((acc, item) => {
    if (!acc[item.category]) {
      acc[item.category] = [];
    }
    acc[item.category].push(item);
    return acc;
  }, {} as Record<string, ShoppingItem[]>);

  // Calculate total price
  const totalPrice = items.reduce((sum, item) => sum + (item.estimatedPrice || 0), 0);

  // State for checked items
  const [checkedItems, setCheckedItems] = useState<Set<string>>(new Set());

  const toggleItem = (itemName: string) => {
    const newChecked = new Set(checkedItems);
    if (newChecked.has(itemName)) {
      newChecked.delete(itemName);
    } else {
      newChecked.add(itemName);
    }
    setCheckedItems(newChecked);
  };

  return (
    <div className="max-w-2xl mx-auto mt-16 pb-20" id="shopping-list-section">
      <div className="relative bg-[#FFFBF7] p-8 md:p-12 shadow-[0_10px_40px_-10px_rgba(0,0,0,0.15)] transform rotate-1 rounded-sm text-[#2C2C2C]">
         {/* Receipt jagged edge top */}
         <div 
            className="absolute top-0 left-0 w-full h-4 bg-repeat-x" 
            style={{ 
                backgroundSize: "20px 20px", 
                backgroundImage: "radial-gradient(circle at 10px -5px, transparent 12px, #FFFBF7 13px)"
            }}
         ></div>

         {/* Receipt jagged edge bottom */}
        <div 
            className="absolute bottom-0 left-0 w-full h-4 bg-repeat-x transform rotate-180" 
            style={{ 
                backgroundSize: "20px 20px", 
                backgroundImage: "radial-gradient(circle at 10px -5px, transparent 12px, #FFFBF7 13px)"
            }}
         ></div>

        <div className="text-center mb-10 border-b-2 border-stone-200 pb-6 border-dashed">
          <h2 className="text-3xl font-serif tracking-tight uppercase">Liste de Courses</h2>
          <p className="text-stone-500 font-mono text-sm mt-2">Ticket Estimatif</p>
        </div>

        <div className="space-y-8">
          {Object.entries(groupedItems).map(([category, categoryItems], categoryIndex) => (
            <motion.div 
              key={category}
              initial={{ opacity: 0, y: 10 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: categoryIndex * 0.1 }}
            >
              <h3 className="text-[#C8553D] font-bold tracking-widest text-xs uppercase mb-4 pl-1">
                {category}
              </h3>
              <ul className="space-y-3">
                {(categoryItems as ShoppingItem[]).map((item, itemIndex) => {
                   const isChecked = checkedItems.has(item.item);
                   return (
                    <li 
                      key={`${category}-${itemIndex}`} 
                      className="flex items-start group cursor-pointer"
                      onClick={() => toggleItem(item.item)}
                    >
                      <div className={`
                        w-5 h-5 mt-0.5 rounded border transition-all duration-200 flex items-center justify-center flex-shrink-0
                        ${isChecked ? 'bg-[#588157] border-[#588157]' : 'border-stone-300 group-hover:border-[#588157]'}
                      `}>
                         {isChecked && (
                           <svg className="w-3.5 h-3.5 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                             <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" />
                           </svg>
                         )}
                      </div>

                      <div className="ml-4 flex-1">
                        <div className="flex justify-between items-baseline">
                          <span className={`
                            font-serif text-lg leading-none transition-all duration-200
                            ${isChecked ? 'text-stone-300 line-through decoration-stone-300' : 'text-stone-800'}
                          `}>
                            {item.item}
                          </span>
                          <span className="font-mono text-sm text-stone-600">
                             {item.estimatedPrice.toFixed(2)} €
                          </span>
                        </div>
                        <div className="flex justify-between items-center mt-1">
                             <span className="font-mono text-xs text-stone-400 bg-stone-100 px-2 py-0.5 rounded">
                                {item.quantity}
                             </span>
                        </div>
                        {item.notes && !isChecked && (
                            <p className="text-xs text-[#588157] mt-1 font-light italic">
                                Note: {item.notes}
                            </p>
                        )}
                      </div>
                    </li>
                  );
                })}
              </ul>
            </motion.div>
          ))}
        </div>

        <div className="mt-10 pt-6 border-t-2 border-dashed border-stone-200">
            <div className="flex justify-between items-end">
                <span className="font-serif text-xl text-stone-600">TOTAL ESTIMÉ</span>
                <span className="font-mono text-3xl font-bold text-[#2C2C2C]">{totalPrice.toFixed(2)} €</span>
            </div>
            <p className="text-xs text-stone-400 mt-2 text-right italic">* Prix moyens observés, peuvent varier en magasin.</p>
        </div>

        <div className="mt-12 text-center font-mono text-xs text-stone-400">
           *** MERCI DE VOTRE VISITE ***
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { UserInput, WeeklyPlanResponse, AppState } from './types';
import { generateWeeklyPlan } from './services/geminiService';
import { InputSection } from './components/InputSection';
import { PlanDisplay } from './components/PlanDisplay';
import { ShoppingList } from './components/ShoppingList';
import { motion, AnimatePresence } from 'framer-motion';
// @ts-ignore
import html2canvas from 'html2canvas';
// @ts-ignore
import { jsPDF } from 'jspdf';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.IDLE);
  const [data, setData] = useState<WeeklyPlanResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  const handleInputSubmit = async (input: UserInput) => {
    setAppState(AppState.LOADING);
    setError(null);
    try {
      const result = await generateWeeklyPlan(input);
      setData(result);
      setAppState(AppState.SUCCESS);
    } catch (err) {
      console.error(err);
      setError("Désolé, nous n'avons pas pu générer votre plan. Veuillez vérifier l'adresse ou réessayer plus tard.");
      setAppState(AppState.ERROR);
    }
  };

  const resetApp = () => {
    setAppState(AppState.IDLE);
    setData(null);
  };

  const downloadPDF = async () => {
    if (!data) return;
    setIsExporting(true);

    try {
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      const planElement = document.getElementById('plan-display-section');
      const shoppingElement = document.getElementById('shopping-list-section');

      if (planElement) {
        // First page: The Plan
        const canvas = await html2canvas(planElement, { scale: 2, useCORS: true, logging: false });
        const imgData = canvas.toDataURL('image/png');
        const imgWidth = pdfWidth - 20;
        const imgHeight = (canvas.height * imgWidth) / canvas.width;

        pdf.setFontSize(18);
        pdf.text("Mon Menu de la Semaine", 10, 15);
        pdf.addImage(imgData, 'PNG', 10, 25, imgWidth, Math.min(imgHeight, pdfHeight - 40));
      }

      if (shoppingElement) {
        // Second page: Shopping List
        pdf.addPage();
        const canvas = await html2canvas(shoppingElement, { scale: 2, useCORS: true, logging: false });
        const imgData = canvas.toDataURL('image/png');
        const imgWidth = pdfWidth - 40; // Narrower for the receipt look
        const imgHeight = (canvas.height * imgWidth) / canvas.width;

        pdf.setFontSize(18);
        pdf.text("Ma Liste de Courses", 10, 15);
        // Center the receipt
        const xPos = (pdfWidth - imgWidth) / 2;
        pdf.addImage(imgData, 'PNG', xPos, 25, imgWidth, Math.min(imgHeight, pdfHeight - 40));
      }

      pdf.save(`Mon_Menu_Marche_et_Menu_${new Date().toLocaleDateString()}.pdf`);
    } catch (err) {
      console.error("Export Error:", err);
      alert("Erreur lors de la génération du PDF. Veuillez réessayer.");
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#F9F8F6] text-[#2C2C2C] selection:bg-[#C8553D] selection:text-white">
      {/* Texture Overlay */}
      <div className="fixed inset-0 pointer-events-none opacity-[0.03] z-50 mix-blend-multiply" 
           style={{ backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")` }}>
      </div>

      <nav className="w-full py-6 px-8 flex justify-between items-center relative z-20">
        <div className="font-serif text-2xl font-bold tracking-tight flex items-center gap-2 cursor-pointer" onClick={resetApp}>
          <span className="w-3 h-3 bg-[#C8553D] rounded-full"></span>
          Marché & Menu
        </div>
        <div className="flex items-center gap-4">
          {appState === AppState.SUCCESS && (
            <>
              <button 
                onClick={downloadPDF}
                disabled={isExporting}
                className="flex items-center gap-2 text-sm font-medium bg-[#C8553D] text-white px-4 py-2 rounded-full hover:bg-black transition-all shadow-sm active:scale-95 disabled:opacity-50"
              >
                {isExporting ? (
                  <>Génération...</>
                ) : (
                  <>
                    <svg xmlns="http://www.w3.org/2000/svg" className="h-4 w-4" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 10v6m0 0l-3-3m3 3l3-3m2 8H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                    </svg>
                    Télécharger PDF
                  </>
                )}
              </button>
              <button 
                onClick={resetApp}
                className="text-sm font-medium hover:text-[#C8553D] transition-colors underline decoration-transparent hover:decoration-[#C8553D] underline-offset-4"
              >
                Nouvelle recherche
              </button>
            </>
          )}
        </div>
      </nav>

      <main className="container mx-auto px-4 pb-20 pt-8 relative z-10">
        <AnimatePresence mode="wait">
          {appState === AppState.IDLE && (
            <motion.div
              key="idle"
              exit={{ opacity: 0, y: -20 }}
              className="flex flex-col items-center justify-center min-h-[70vh]"
            >
               <InputSection onSubmit={handleInputSubmit} isLoading={false} />
            </motion.div>
          )}

          {appState === AppState.LOADING && (
            <motion.div
              key="loading"
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0, scale: 0.95 }}
              className="flex flex-col items-center justify-center min-h-[60vh] text-center"
            >
               <div className="w-24 h-24 mb-8 relative">
                  <motion.div 
                     className="absolute inset-0 border-4 border-stone-200 rounded-full"
                  />
                  <motion.div 
                     className="absolute inset-0 border-4 border-t-[#C8553D] border-r-[#C8553D] border-b-transparent border-l-transparent rounded-full"
                     animate={{ rotate: 360 }}
                     transition={{ duration: 1.5, repeat: Infinity, ease: "linear" }}
                  />
               </div>
               <h3 className="text-2xl font-serif text-[#2C2C2C] mb-2">Nos chefs réfléchissent...</h3>
               <p className="text-stone-500 max-w-md mx-auto">
                 Nous analysons les produits disponibles autour de votre adresse pour composer le menu parfait.
               </p>
            </motion.div>
          )}

          {appState === AppState.ERROR && (
             <motion.div
                key="error"
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                className="flex flex-col items-center justify-center min-h-[50vh] text-center"
             >
                <div className="text-[#C8553D] mb-4">
                  <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 mx-auto" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={1.5} d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                  </svg>
                </div>
                <h3 className="text-xl font-bold mb-2">Oups, une erreur est survenue</h3>
                <p className="text-stone-600 mb-6">{error}</p>
                <button 
                  onClick={resetApp}
