import { GoogleGenAI } from "@google/genai";
import { WeeklyPlanResponse, UserInput } from "../types";

const apiKey = process.env.API_KEY;

export const generateWeeklyPlan = async (input: UserInput): Promise<WeeklyPlanResponse> => {
  if (!apiKey) throw new Error("Clé API manquante dans l'environnement.");

  const ai = new GoogleGenAI({ apiKey: apiKey });

  const prompt = `
    Agis comme un chef personnel et un expert en logistique alimentaire.

    INFORMATIONS UTILISATEUR:
    - Adresse : "${input.address}"
    - Supermarché cible : "${input.supermarket}"
    - Nombre de personnes : ${input.peopleCount}
    ${input.budget ? `- Budget Maximum souhaité : ${input.budget}` : ''}
    ${input.diet ? `- Régime spécifique : ${input.diet}` : ''}
    ${input.unwantedIngredients ? `- Ingrédients non souhaités : ${input.unwantedIngredients}` : ''}

    TÂCHES:
    1. **Localisation** : Localise ce supermarché précis près de l'adresse.
    2. **Menu** : Crée un plan de 7 jours (21 repas) pour ${input.peopleCount} personnes.
    3. **Courses** : Génère la liste de courses avec des prix estimés pour l'enseigne "${input.supermarket}".

    IMPORTANT : Renvoie UNIQUEMENT un objet JSON valide.

    FORMAT JSON:
    {
      "locationConfirmed": "string",
      "supermarketContext": "string",
      "weeklyPlan": [
        {
          "day": "Lundi",
          "breakfast": { "name": "...", "description": "...", "cookingTimeMinutes": 10, "recipe": { "ingredients": [], "instructions": [] } },
          "lunch": { ... },
          "dinner": { ... }
        }
      ],
      "shoppingList": [
        { "category": "...", "item": "...", "quantity": "...", "notes": "...", "estimatedPrice": 0.0 }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        responseMimeType: "application/json"
      },
    });

    const text = response.text;
    if (!text) throw new Error("Réponse vide de l'IA");

    return JSON.parse(text) as WeeklyPlanResponse;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

