  const [data, setData] = useState<WeeklyPlanResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [isExporting, setIsExporting] = useState(false);

  const handleInputSubmit = async (input: UserInput) => {
    setAppState(AppState.LOADING);
    setError(null);
    try {
      const result = await generateWeeklyPlan(input);
      setData(result);
      setAppState(AppState.SUCCESS);
    } catch (err) {
      console.error(err);
      setError("Impossible de générer le plan. Vérifiez votre connexion ou l'adresse saisie.");
      setAppState(AppState.ERROR);
    }
  };

  const resetApp = () => {
    setAppState(AppState.IDLE);
    setData(null);
    setError(null);
  };

  const downloadPDF = async () => {
    if (!data) return;
    setIsExporting(true);

    try {
      const pdf = new jsPDF('p', 'mm', 'a4');
      const pdfWidth = pdf.internal.pageSize.getWidth();
      const pdfHeight = pdf.internal.pageSize.getHeight();

      const planElement = document.getElementById('plan-display-section');
      const shoppingElement = document.getElementById('shopping-list-section');

      if (planElement) {
        const canvas = await html2canvas(planElement, { scale: 1.5, useCORS: true });
        const imgData = canvas.toDataURL('image/png');
        const imgWidth = pdfWidth - 20;
        const imgHeight = (canvas.height * imgWidth) / canvas.width;

        pdf.setFontSize(16);
        pdf.text("Mon Menu Hebdomadaire", 10, 15);
        pdf.addImage(imgData, 'PNG', 10, 20, imgWidth, Math.min(imgHeight, pdfHeight - 30));
      }

      if (shoppingElement) {
        pdf.addPage();
        const canvas = await html2canvas(shoppingElement, { scale: 1.5, useCORS: true });
        const imgData = canvas.toDataURL('image/png');
        const imgWidth = pdfWidth - 30;
        const imgHeight = (canvas.height * imgWidth) / canvas.width;

        pdf.setFontSize(16);
        pdf.text("Ma Liste de Courses", 10, 15);
        const xPos = (pdfWidth - imgWidth) / 2;
        pdf.addImage(imgData, 'PNG', xPos, 20, imgWidth, Math.min(imgHeight, pdfHeight - 30));
      }

      pdf.save(`Menu_Marche_${new Date().getTime()}.pdf`);
    } catch (err) {
      console.error("PDF Export Error:", err);
      alert("Erreur lors de la création du PDF.");
    } finally {
      setIsExporting(false);
    }
  };

  return (
    <div className="min-h-screen bg-[#F9F8F6] text-[#2C2C2C] selection:bg-[#C8553D] selection:text-white">
      <div className="fixed inset-0 pointer-events-none opacity-[0.03] z-50 mix-blend-multiply" 
           style={{ backgroundImage: `url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noiseFilter'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noiseFilter)'/%3E%3C/svg%3E")` }}>
      </div>

      <nav className="w-full py-6 px-8 flex justify-between items-center relative z-20">
        <div className="font-serif text-2xl font-bold tracking-tight flex items-center gap-2 cursor-pointer" onClick={resetApp}>
          <span className="w-3 h-3 bg-[#C8553D] rounded-full"></span>
          Marché & Menu
        </div>
        {appState === AppState.SUCCESS && (
          <div className="flex gap-4">
            <button onClick={downloadPDF} disabled={isExporting} className="text-sm font-medium bg-[#C8553D] text-white px-4 py-2 rounded-full hover:bg-black transition-all">
              {isExporting ? "Chargement..." : "Télécharger PDF"}
            </button>
            <button onClick={resetApp} className="text-sm font-medium hover:text-[#C8553D]">Nouveau</button>
          </div>
        )}
      </nav>

      <main className="container mx-auto px-4 pb-20 pt-8 relative z-10">
        <AnimatePresence mode="wait">
          {appState === AppState.IDLE && (
            <motion.div key="idle" exit={{ opacity: 0, y: -20 }}>
               <InputSection onSubmit={handleInputSubmit} isLoading={false} />
            </motion.div>
          )}

          {appState === AppState.LOADING && (
            <motion.div key="loading" className="flex flex-col items-center justify-center min-h-[50vh] text-center">
               <div className="w-16 h-16 mb-6 border-4 border-stone-200 border-t-[#C8553D] rounded-full animate-spin" />
               <h3 className="text-xl font-serif">Composition de votre menu...</h3>
            </motion.div>
          )}

          {appState === AppState.ERROR && (
             <motion.div key="error" className="flex flex-col items-center justify-center min-h-[40vh] text-center">
                <p className="text-[#C8553D] mb-4">{error}</p>
                <button onClick={resetApp} className="px-6 py-2 bg-[#2C2C2C] text-white rounded-lg">Réessayer</button>
             </motion.div>
          )}

          {appState === AppState.SUCCESS && data && (
            <motion.div key="success" initial={{ opacity: 0 }} animate={{ opacity: 1 }}>
              <PlanDisplay 
                plan={data.weeklyPlan} 
                supermarketContext={data.supermarketContext} 
                locationConfirmed={data.locationConfirmed}
              />
              <ShoppingList items={data.shoppingList} />
            </motion.div>
          )}
        </AnimatePresence>
      </main>

      <footer className="text-center py-8 text-stone-400 text-xs">
         <p>© {new Date().getFullYear()} Marché & Menu.</p>
      </footer>
    </div>
  );
};

