export const generateWeeklyPlan = async (input: UserInput): Promise<WeeklyPlanResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Clé API manquante.");

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Agis comme un chef personnel expert.

    PARAMÈTRES:
    - Lieu: "${input.address}"
    - Magasin: "${input.supermarket}"
    - Personnes: ${input.peopleCount}
    - Budget: ${input.budget || 'Non spécifié'}
    - Régime: ${input.diet || 'Omnivore'}
    - Allergies/Exclusions: ${input.unwantedIngredients || 'Aucune'}

    OBJECTIFS:
    1. Localise précisément le magasin "${input.supermarket}" près de "${input.address}".
    2. Génère un menu de 7 jours (petit-déjeuner, déjeuner, dîner) adapté à ${input.peopleCount} personnes.
    3. Produis une liste de courses détaillée avec prix estimés chez "${input.supermarket}".

    REPONDS UNIQUEMENT EN JSON avec cette structure:
    {
      "locationConfirmed": "Adresse exacte trouvée",
      "supermarketContext": "Bref avis sur le magasin",
      "weeklyPlan": [{
        "day": "Lundi",
        "breakfast": { "name": "", "description": "", "cookingTimeMinutes": 10, "recipe": { "ingredients": [], "instructions": [] } },
        "lunch": { ... },
        "dinner": { ... }
      }],
      "shoppingList": [{ "category": "", "item": "", "quantity": "", "notes": "", "estimatedPrice": 0.0 }]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        responseMimeType: "application/json"
      },
    });

    const text = response.text;
    if (!text) throw new Error("Pas de contenu généré.");

    return JSON.parse(text) as WeeklyPlanResponse;
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

import { GoogleGenAI } from "@google/genai";
import { WeeklyPlanResponse, UserInput } from "../types";

export const generateWeeklyPlan = async (input: UserInput): Promise<WeeklyPlanResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Clé API manquante.");

  const ai = new GoogleGenAI({ apiKey });

  const prompt = `
    Agis comme un chef personnel expert en nutrition et logistique locale.

    PARAMÈTRES UTILISATEUR:
    - Lieu : "${input.address}"
    - Enseigne souhaitée : "${input.supermarket}"
    - Nombre de personnes : ${input.peopleCount}
    - Budget : ${input.budget || 'Non spécifié'}
    - Régime : ${input.diet || 'Omnivore'}
    - Allergies/Exclusions : ${input.unwantedIngredients || 'Aucune'}

    TES MISSIONS :
    1. Utilise Google Maps pour localiser précisément un magasin de l'enseigne "${input.supermarket}" à proximité de "${input.address}".
    2. Crée un menu complet de 7 jours (21 repas) sain, varié et respectant les contraintes de l'utilisateur.
    3. Génère une liste de courses détaillée avec des prix estimés correspondant aux tarifs habituels de "${input.supermarket}".

    IMPORTANT : Tu dois répondre EXCLUSIVEMENT avec un bloc de code JSON. Ne mets aucune phrase avant ou après le JSON.

    STRUCTURE DU JSON :
    {
      "locationConfirmed": "Nom et adresse précise du magasin trouvé",
      "supermarketContext": "Une phrase sur les points forts de ce magasin pour ces recettes",
      "weeklyPlan": [
        {
          "day": "Lundi",
          "breakfast": { "name": "Nom", "description": "Desc", "cookingTimeMinutes": 10, "recipe": { "ingredients": ["1 unité de x"], "instructions": ["Faire x"] } },
          "lunch": { ... },
          "dinner": { ... }
        }
      ],
      "shoppingList": [
        { "category": "Rayon", "item": "Produit", "quantity": "Nombre/Poids", "notes": "Optionnel", "estimatedPrice": 0.0 }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-latest",
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        // Note: responseMimeType: "application/json" est INTERDIT avec l'outil Google Maps.
      },
    });

    const text = response.text;
    if (!text) throw new Error("Pas de contenu généré par l'IA.");

    // Extraction du JSON car le modèle peut renvoyer du texte explicatif ou des blocs markdown
    const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/) || text.match(/{[\s\S]*}/);
    const jsonString = jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : text;

    try {
        return JSON.parse(jsonString.trim()) as WeeklyPlanResponse;
    } catch (parseError) {
        console.error("Erreur de parsing JSON:", text);
        throw new Error("La réponse de l'IA n'est pas au format JSON valide.");
    }
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

