import { GoogleGenAI } from "@google/genai";
import { WeeklyPlanResponse, UserInput, GroundingSource } from "../types";

export const generateWeeklyPlan = async (input: UserInput): Promise<WeeklyPlanResponse> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("Clé API manquante.");

  const ai = new GoogleGenAI({ apiKey });

  // Tentative de récupération des coordonnées GPS pour aider le grounding Google Maps
  let latLng: { latitude: number; longitude: number } | undefined = undefined;
  try {
    const position = await new Promise<GeolocationPosition>((resolve, reject) => {
      navigator.geolocation.getCurrentPosition(resolve, reject, { timeout: 3000 });
    });
    latLng = {
      latitude: position.coords.latitude,
      longitude: position.coords.longitude
    };
  } catch (e) {
    console.debug("Location access denied or unavailable, using address only.");
  }

  const prompt = `
    Agis comme un chef personnel expert en nutrition et logistique locale.

    PARAMÈTRES UTILISATEUR:
    - Lieu : "${input.address}"
    - Enseigne souhaitée : "${input.supermarket}"
    - Nombre de personnes : ${input.peopleCount}
    - Budget : ${input.budget || 'Non spécifié'}
    - Régime : ${input.diet || 'Omnivore'}
    - Allergies/Exclusions : ${input.unwantedIngredients || 'Aucune'}

    TES MISSIONS :
    1. Utilise Google Maps pour localiser précisément un magasin de l'enseigne "${input.supermarket}" à proximité de "${input.address}".
    2. Crée un menu complet de 7 jours (21 repas) sain, varié et respectant les contraintes de l'utilisateur.
    3. Génère une liste de courses détaillée avec des prix estimés correspondant aux tarifs habituels de "${input.supermarket}".

    IMPORTANT : Tu dois répondre EXCLUSIVEMENT avec un bloc de code JSON. Ne mets aucune phrase avant ou après le JSON.

    STRUCTURE DU JSON :
    {
      "locationConfirmed": "Nom et adresse précise du magasin trouvé",
      "supermarketContext": "Une phrase sur les points forts de ce magasin pour ces recettes",
      "weeklyPlan": [
        {
          "day": "Lundi",
          "breakfast": { "name": "Nom", "description": "Desc", "cookingTimeMinutes": 10, "recipe": { "ingredients": ["1 unité de x"], "instructions": ["Faire x"] } },
          "lunch": { "name": "Nom", "description": "Desc", "cookingTimeMinutes": 20, "recipe": { "ingredients": [], "instructions": [] } },
          "dinner": { "name": "Nom", "description": "Desc", "cookingTimeMinutes": 30, "recipe": { "ingredients": [], "instructions": [] } }
        }
      ],
      "shoppingList": [
        { "category": "Rayon", "item": "Produit", "quantity": "Nombre/Poids", "notes": "Optionnel", "estimatedPrice": 0.0 }
      ]
    }
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: prompt,
      config: {
        tools: [{ googleMaps: {} }],
        toolConfig: latLng ? {
          retrievalConfig: {
            latLng: latLng
          }
        } : undefined
      },
    });

    const text = response.text;
    if (!text) throw new Error("Pas de contenu généré par l'IA.");

    // Extraction des sources Google Maps pour affichage obligatoire
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const sources: GroundingSource[] = [];

    if (groundingChunks) {
      groundingChunks.forEach((chunk: any) => {
        if (chunk.maps) {
          sources.push({ title: chunk.maps.title, uri: chunk.maps.uri });
        }
      });
    }

    const jsonMatch = text.match(/```json\n([\s\S]*?)\n```/) || text.match(/{[\s\S]*}/);
    const jsonString = jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : text;

    try {
        const parsed = JSON.parse(jsonString.trim()) as WeeklyPlanResponse;
        return { ...parsed, sources };
    } catch (parseError) {
        console.error("Erreur de parsing JSON:", text);
        throw new Error("La réponse de l'IA n'est pas au format JSON valide.");
    }
  } catch (error: any) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

